import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import styles from './Layout.module.css';

import { auth } from '../../firebase';
import { signOut } from 'firebase/auth';
import { toast } from 'react-toastify';

const Sidebar = () => {
  const navigate = useNavigate();

  const handleLogout = async () => {
    try {
      await signOut(auth);
      toast.success('Logged out successfully');
      navigate('/login');
    } catch (error) {
      toast.error('Failed to log out');
    }
  };

  return (
    <div className={styles.sidebar}>
      <div className={styles.logoContainer}>
        <div className={styles.logo}>
          {/* Placeholder for Campus Logo */}
          <div style={{ color: 'black', fontWeight: 'bold', textAlign: 'center' }}>
            <span style={{color: 'darkblue', fontSize: '24px'}}>HORIZON</span><br/>
            <span style={{color: 'red', fontSize: '12px'}}>CAMPUS</span>
          </div>
        </div>
        <div className={styles.brandName}>HORIZON CAMPUS</div>
        <div className={styles.brandSubName}>Stationary Inventory</div>
      </div>

      <nav className={styles.navLinks}>
        <NavLink 
          to="/dashboard" 
          className={({ isActive }) => isActive ? `${styles.navItem} ${styles.activeNavItem}` : styles.navItem}
        >
          Dashboard
        </NavLink>
        <NavLink 
          to="/inventory" 
          className={({ isActive }) => isActive ? `${styles.navItem} ${styles.activeNavItem}` : styles.navItem}
        >
          Inventory
        </NavLink>
        <NavLink 
          to="/issue-item" 
          className={({ isActive }) => isActive ? `${styles.navItem} ${styles.activeNavItem}` : styles.navItem}
        >
          Issue Item
        </NavLink>
        <NavLink 
          to="/return-item" 
          className={({ isActive }) => isActive ? `${styles.navItem} ${styles.activeNavItem}` : styles.navItem}
        >
          Return Item
        </NavLink>
        <NavLink 
          to="/request-item" 
          className={({ isActive }) => isActive ? `${styles.navItem} ${styles.activeNavItem}` : styles.navItem}
        >
          Request Item
        </NavLink>
        <NavLink 
          to="/reports" 
          className={({ isActive }) => isActive ? `${styles.navItem} ${styles.activeNavItem}` : styles.navItem}
        >
          Reports
        </NavLink>
        <NavLink 
          to="/user" 
          className={({ isActive }) => isActive ? `${styles.navItem} ${styles.activeNavItem}` : styles.navItem}
        >
          User
        </NavLink>
        <NavLink 
          to="/contact-us" 
          className={({ isActive }) => isActive ? `${styles.navItem} ${styles.activeNavItem}` : styles.navItem}
        >
          Contact Us
        </NavLink>
      </nav>

      <div className={styles.logoutSection}>
        <button className={styles.logoutButton} onClick={handleLogout}>
          Log Out
        </button>
      </div>
    </div>
  );
};

export default Sidebar;
